+        ops.add(Expression.make(INTS,  "Integer.signum(", INTS, ")"));
+        ops.add(Expression.make(INTS,  "Integer.sum(", INTS, ", ", INTS, ")"));
+        ops.add(Expression.make(LONGS, "Integer.toUnsignedLong(", INTS, ")"));
