+            String name = m.getType().getName() + "::" + m.getName();
+            map.compute(name, (_, value) -> (value == null) ? 1 : value + 1);
+        }
+        for (var e : map.entrySet()) {
+            System.out.println(e.getKey() + " " + e.getValue());
+        }
+        return map;
+    }
